var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"모두 무사해?","JPN":"みんな無事？","ENG":"Is everyone all right?","TWN":"大家都沒事吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"다행히 그리 많은 숫자는 아니었군.","JPN":"幸い、数はそこまで多くなかった。","ENG":"Thankfully, there aren't a lot of them.","TWN":"還好，數量不多。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"아무리 생각해도 이상해.","JPN":"どう考えてもおかしい。","ENG":"But it still doesn't add up no matter how I look at it.","TWN":"不管怎麼想都覺得很奇怪。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"봐라. 침식체에서 추출한 이터니움. 저번처럼 검은색을 띠고 있어.","JPN":"ほら、侵食体から抽出したエタニウム……この前みたいに黒ずんでいる。","ENG":"Look. The Eternium we extracted from the C.O.s. It's black like last time.","TWN":"你們看，這次從侵蝕體中拿出來的永恆之金，和上次一樣是黑色的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그럼 또 불량이겠네요.","JPN":"じゃあまた不良品ですね。","ENG":"It's another defect.","TWN":"那又是瑕疵品了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"역시 좋지 않은 예감이 들어….","JPN":"やはり、悪い予感がする……","ENG":"I don't like where this is going...","TWN":"我有不好的預感……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"빨리 마을에 알려야 해요. 무언가 대비책이라도 세워야죠.","JPN":"早く村に知らせましょう。何か対策を立てないと。","ENG":"We have to alert the village and come up with some kind of plan.","TWN":"得趕緊通知村子，必須想個對策。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그래. 서두르자.","JPN":"ああ、急ぐぞ。","ENG":"Yeah. Let's hurry.","TWN":"嗯，快走吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그 전에 마브카. 너에게 할 말이 있다.","JPN":"その前に、マブカ。お前に話がある。","ENG":"Before that, Mavka. I need to speak with you.","TWN":"走之前，瑪卡，我有話對你說。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그 때 잠깐 봤다고 해서, 친해졌다 생각하는건 아니겠지?","JPN":"ちょっと話しただけで仲よくなったと思ってるわけじゃないだろうな。","ENG":"You're not thinking that we're friends just because we briefly talked last time, are you?","TWN":"你不會覺得我們只是見了幾次面，我就完全相信你了吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"역시 우리에겐 확신이 필요해.","JPN":"やはり俺たちには確信が必要だ。","ENG":"We can't really trust you yet.","TWN":"我們還需要一個確據。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그, 그치만 마브카는 여기서 수상한 짓은 안 했잖아요.","JPN":"で、でも。マブカはここで怪しいことは何もしてませんよ。","ENG":"B-but Mavka didn't do anything suspicious.","TWN":"但，但是瑪卡在這裡沒有做過什麼可疑的事啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"사샤. 넌 착한 아이다만, 너무 무른면이 있어.","JPN":"サシャ、お前は優しいが、甘いところがある。","ENG":"Sasha. You're a good kid, but you're also naive.","TWN":"莎夏，你是個好孩子，但有點太軟弱了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"곰과 우정을 나누되, 언제나 손도끼를 준비해 둬야지.","JPN":"熊と友情を結ぼうとも、常に手斧を準備しておくべきだ。","ENG":"If you're going to befriend a bear, you must keep a hatchet by your side.","TWN":"和熊交朋友，但手邊總要準備好斧頭。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"우리 입장에선 어쩔 수 없다.","JPN":"俺たちからすると仕方ないんだ。","ENG":"We have no other choice in this situation.","TWN":"從我們的立場來看也是沒辦法的事。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……내가 뭘 하면 될까?","JPN":"……私は何をすればいい？","ENG":"...Then what do you want me to do?","TWN":"……那我該做什麼呢？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"네가 적이 아니라는 것을 증명해. 그럼 믿도록 하지.","JPN":"お前が敵じゃないということを証明してほしい。信じるのはそれからだ。","ENG":"Give us proof that you're not our enemy. Then, we'll trust you.","TWN":"證明你不是敵人。那我就相信你。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"증명….","JPN":"証明……","ENG":"Proof...","TWN":"證明……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"알았어.","JPN":"わかった。","ENG":"Okay.","TWN":"知道了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_02"},{"id":"L40_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"몸을 열었다고? 이건…?!","JPN":"体を開いた？　これは……！？","ENG":"Her upper body just opened? That's...!","TWN":"打開身體？腹部？這是……？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이건 <color=#ffd34c>메모리 코어</color>. 내 기억을 보관하는 장치이자, 약점이라고 할 수 있지.","JPN":"これは<color=#ffd34c>メモリーコア</color>。私の記憶を保管する装置であり、弱点でもある。","ENG":"This is a <color=#ffd34c>memory core</color>. It is used to store my memories and it's also my weakness.","TWN":"這是<color=#ffd34c>記憶核心</color>。是保存我記憶的裝置，也可以說是我的弱點。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"지금 내 몸은 어떠한 부위도 인간이라 할 수 있는 게 남아있지 않아.","JPN":"今の私の体に、人間と呼べるような部位はもう残っていない。","ENG":"There is no part of my body that can be called human.","TWN":"現在我的身體已經沒有任何部位可以稱之為人類了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"유일하게 남은 것은 나의 기억뿐.","JPN":"唯一残っているのは私の記憶だけ。","ENG":"The only thing remaining is my memories.","TWN":"唯一剩下的只有我的記憶。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아저씨, 아까 원격조작이 가능한 폭탄을 들고 있었지?","JPN":"さっき、リモートコントロールができる爆弾を持っていたよね。","ENG":"You said you had a remotely detonative bomb with you, right?","TWN":"大叔，你那邊有可以遠端操控的炸彈吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"필요하다면 장착해도 좋아.","JPN":"それをここにつけてもいいよ。","ENG":"You can install that in me if you want.","TWN":"如果需要的話，可以裝上。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카!","JPN":"マブカ！","ENG":"Mavka!","TWN":"瑪卡！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"내가 적이라고 확신이 서면 이걸 터트리면 돼.","JPN":"私が敵だと思った時は、それを爆発させればいい。","ENG":"If you are sure that I'm the enemy, you can detonate it.","TWN":"如果你確定我是敵人，就引爆它。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"내가 고철 더미에 추락했을 때, 코어는 분명 파괴되었어.","JPN":"私が古鉄の山に墜落した時、コアは確かに破壊されたはず……","ENG":"When I fell into the pile of junk, my core was definitely destroyed.","TWN":"我掉到廢鐵堆裡時，核心確實被破壞了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"하지만 깨어난 뒤엔, 어째서인지 고쳐져 있었지.","JPN":"でも目を覚ました時は、なぜか直っていた。","ENG":"But when I woke up again, it was fixed for some reason.","TWN":"但醒來後，不知為何又修好了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤가 날 구해준 거야.","JPN":"サシャが私を助けてくれた。","ENG":"Sasha saved me.","TWN":"是莎夏救了我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤는 내 은인이야. 그 보답으로 곁에서 지켜주기로 결심했어.","JPN":"サシャは私の恩人だ。そのお礼に、私はサシャの側で彼女を守ろうと決めた。","ENG":"I owe my life to Sasha. In return, I've decided to protect her by her side.","TWN":"莎夏是我的恩人。作為報答，我決定在她身邊守護她。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"………!!!","JPN":"……！！","ENG":"...!!!","TWN":"………！！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"내가 북방군에 입대했던 것도 사람들과 세상을 지키기 위해서였어.","JPN":"私が北方軍に入隊したのも、人々と世界を守るためだった。","ENG":"I joined the Northern Army to protect the world and its people.","TWN":"我加入北方軍也是為了保護眾人和世界。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"어쨌든 살아가게 된 이상 내 신념은 계속되어야 한다고 생각해.","JPN":"経緯はどうであれ、生きていくことになった以上私は信念を貫くつもり。","ENG":"As long as I continue to live, I think I should keep my determination.","TWN":"既然活下來了，我的信念就必須繼續下去。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이 정도면 확신이 설까?","JPN":"これで確信が持てるかな。","ENG":"Now, is that enough to convince you?","TWN":"這樣能讓你相信嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"혀, 형님… 설마 진짜로 장착할거야?","JPN":"あ、兄貴……まさか本当につけるんですか？","ENG":"S-sir...! Are you really going to put that in her?","TWN":"安哥……真的要裝上去嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"당신…!","JPN":"あなた……！","ENG":"Hey...!","TWN":"你……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"하나부터 열까지 꼬맹이가 할 법한 행동이 아니군.","JPN":"何から何まで、ガキのやることではないな。","ENG":"Everything you've done is not something a child would do.","TWN":"從頭到尾都不像是小鬼會做的事。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"약점의 위치는 알았으니 됐다. 굳이 폭탄까지 장착할 필요는 없겠지.","JPN":"弱点の場所がわかったからいい。あえて爆弾を仕掛ける必要はないだろう。","ENG":"Knowing your weak spot is enough. I don't need to plant a bomb inside you.","TWN":"知道了弱點，就沒必要裝炸彈了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"하지만 확신이 서게 된다면, 난 절대 망설이지 않을거다.","JPN":"だが、確信ができたら私は決して迷わない。","ENG":"But when I am convinced that you are the enemy, I won't hesitate to kill you.","TWN":"但如果我確認你是敵人，我絕不會猶豫。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"사샤를 봐서 이 정도로 넘어가 주는거라 생각해라.","JPN":"サシャに免じて、この辺で許してやる。","ENG":"I'll stop here for Sasha's sake.","TWN":"看在莎夏的份上，就到此為止吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"……이만 돌아가지.","JPN":"……帰るぞ。","ENG":"...Let's head back.","TWN":"……我們回去吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤… 에헤헤….","JPN":"えへ……えへへ……","ENG":"Hehe... Ehehe...","TWN":"嘿嘿……欸嘿嘿……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"………?","JPN":"………?","ENG":"...?","TWN":"………？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"히히… 이히히…!","JPN":"ひひ……いひひっ……！","ENG":"Hehe... Hehehe...!","TWN":"嘻嘻……嘻嘻嘻……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L31_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"옆에서 이상한 소리 좀 내지 말아줄래? 변태도 아니고.","JPN":"ちょっと、その変な声やめてくれる？　変態みたいなんだけど。","ENG":"Will you stop making weird noises? It's creeping me out.","TWN":"能不能別在旁邊發出奇怪的聲音？又不是變態。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아, 아니 난 그냥….","JPN":"い、いや……","ENG":"Oh, I-I just...","TWN":"啊，不，我只是……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아까… 날 위해서 살아주겠다는 말이 계속 생각나서. 에, 에헤헤….","JPN":"さっき……私のために生きてくれるって言ったのが頭から離れなくて。え、えへへ……","ENG":"You know... I kept thinking of what you said about living for me. E-ehehe...","TWN":"剛才……我一直想著……你說要為我而活的那些話。嘿嘿，欸嘿嘿……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그렇게까진 말 안 했어.","JPN":"そこまでは言っていない。","ENG":"I didn't say it to that extent.","TWN":"我沒說得那麼誇張。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"하지만… 이걸로 사람들이 날 믿어줄까?","JPN":"でも……これで皆、私を信じてくれるかな。","ENG":"But... will the others trust me now?","TWN":"但是……這樣他們會相信我嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"너무 걱정하지마. 아저씨도 처음부터 널 나쁘게 생각하진 않으셨을거야.","JPN":"あまり心配しないで。おじさんだって、きっと本当はそんなにあなたのこと悪く思ってないよ。","ENG":"Don't worry. They never thought badly of you from the start.","TWN":"不用擔心，大叔一開始也不會對你有壞印象的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"지금쯤 엄청 마음 졸이고 계실게 분명해.","JPN":"今頃悪いことしたと思ってるに違いないって。","ENG":"I'm sure they're all just really anxious.","TWN":"現在他肯定非常愧疚。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤… 나를 위해 목숨을 걸어주는 친구라니….","JPN":"えへへ……私のために命をかけてくれる友だち……","ENG":"Hehe... But I now have a friend who will risk her life for me...","TWN":"嘿嘿……為了我連命都願意豁出去的朋友啊……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아… 이런 건 심장에 좋지 않아….","JPN":"こ、こんなの心臓によくない……","ENG":"Ah... This is making my heart race too much...","TWN":"啊……這種事對心臟不好……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"얼굴도 엄청 새빨개져선… 평소보다 더 바보 같아 보여.","JPN":"真っ赤になっちゃって……いつもよりあほっぽい。","ENG":"Your face is beet red... and you look stupider than usual.","TWN":"你臉都紅透了……看起來比平時更傻。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아… 너무 좋아서 쓰러질 것 만 같아… 이렇게까지 몸이 뜨거워졌다니까?","JPN":"あ……嬉しすぎて倒れそう……ほら、こんなに体が熱くなって……","ENG":"Ah... I got so happy, I was blushing so much that I thought I might faint.","TWN":"啊……太開心了，感覺要暈倒了……身體好熱欸？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L42_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤. 이제 장난 좀 그만…!","JPN":"サシャ、もう冗談はやめ……！","ENG":"Sasha, enough fooling around–!","TWN":"莎夏。別再開玩笑了……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤…?","JPN":"サシャ…？","ENG":"Sasha...?","TWN":"莎夏……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"무슨 일이야?","JPN":"どうした？","ENG":"What's wrong?","TWN":"什麼事？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤가 쓰러졌어! 어떻게 된 거지?","JPN":"サシャが倒れた！　どうしたんだろ……？","ENG":"Sasha's fainted! What's happening to her?!","TWN":"莎夏暈倒了！怎麼回事？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"열이 심하군. 서둘러야겠어.","JPN":"熱がひどい。急がないと。","ENG":"She has a fever. We must hurry.","TWN":"發燒很嚴重，快送她回去。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};